import redis
from rediscluster import RedisCluster

# Function to connect to Redis cluster
def connect_to_redis():
    startup_nodes = [
        {"host": "redis-node1", "port": "6379"},
        {"host": "redis-node2", "port": "6379"},
        {"host": "redis-node3", "port": "6379"}
    ]
    return RedisCluster(startup_nodes=startup_nodes, decode_responses=True)

# Function to store session token in Redis with TTL
def store_session_token(session_id, user_data, ttl=3600):
    redis_client = connect_to_redis()
    redis_client.setex(session_id, ttl, user_data)
    redis_client.close()

# Function to retrieve session token from Redis
def get_session_token(session_id):
    redis_client = connect_to_redis()
    token = redis_client.get(session_id)
    redis_client.close()
    return token

# Example usage
session_id = "user123"
user_data = {"api_key": "abc123", "session_expiry": 3600}
store_session_token(session_id, user_data)

retrieved_token = get_session_token(session_id)
print(retrieved_token)